/////////
// CDC //
/////////
// Includes 2FF sync for sys_tpm_rst_ni, which asserts asynchronously to
// sys_clk_i. The synchronizer output feeds logic that determines when to
// release the RdFIFO to SW. The posedge_pulse output is used to latch the TPM
// configuration and return-by-hw register values for use in the current
// command.
// The outputs of the edge detector are thus delayed another 2 SYS_CLK cycles
// after the prim_rst_sync. The configuration latches into SYS_CLK below,
// and those outputs are used on the 24th bit of the SPI clock. So, SYS_CLK
// must be at least 1/4 the frequency as the SPI clock.
prim_edge_detector #(
  .Width      (1),
  .ResetValue (1'b 0),
  .EnSync     (1'b 1)
) u_csb_sync_rst (
  .clk_i             (sys_clk_i),
  .rst_ni            (sys_rst_ni),
  .d_i               (sys_tpm_rst_ni),
  .q_sync_o          (),
  .q_posedge_pulse_o (sys_csb_asserted_pulse),
  .q_negedge_pulse_o (sys_csb_deasserted_pulse)
);

// Pass control of the WrFIFO from hardware to software when write commands
// are written into the CmdAddrFIFO, and release it back from software to
// hardware when software issues the instruction.
prim_flop_2sync #(
  .Width     (1)
) u_wrfifo_busy_sync (
  .clk_i     (sys_clk_i),
  .rst_ni    (sys_rst_ni),
  .d_i       (sck_wrfifo_busy),
  .q_o       (sys_wrfifo_busy)
);

// SYS-originated address mode changes must only occur while SPI is inactive.
// The SPI flash protocol and hardware view would be violated otherwise.
// Thus, the data will always be stable by the time the SPI domain picks it up.
prim_sync_reqack_data #(
  .Width (1)
) u_sys2spi_sync (
  .clk_src_i        (sys_clk_i),
  .rst_src_ni       (sys_rst_ni),
  .clk_dst_i        (spi_clk_i),
  .rst_dst_ni       (sys_rst_ni),
  .req_chk_i        (1'b1),
  .src_req_i        (sys_fw_new_addr_mode_req),
  .src_ack_o        (sys_fw_new_addr_mode_ack),
  .dst_req_o        (spi_fw_new_addr_mode_req),
  .dst_ack_i        (spi_fw_new_addr_mode_ack),
  .data_i           (sys_fw_new_addr_mode_data),
  .data_o           (spi_fw_new_addr_mode_data)
);

// clk_i is asynchronous to CSB/SCK, so use a synchronizer.
prim_flop_2sync #(
  .Width     (1)
) u_count_sync (
  .clk_i,
  .rst_ni,
  .d_i       (csb_toggle),
  .q_o       (sys_toggle)
);

// Staged to Committed at CSb de-assertion
// SW and the passthrough gate only receive the final values of
// a transaction.
