  .Width      ($bits(sck_status_committed)),
  .ResetValue ('0)
) u_sck2csb_status (
  .clk_i  (clk_csb_i),
  .rst_ni (sys_rst_ni),
  .d_i    (sck_status_committed),
  .q_o    (csb_status_committed)
);

